#!/usr/bin/env bash
set -euo pipefail

# Order fields
SELL_TOKEN="0x4200000000000000000000000000000000000006"
BUY_TOKEN="0xc1cba3fcea344f92d9239c08c0568f6f2f0ee452"
RECEIVER="0xb4755fae3997fbe4becd34b4fc5a7f53d3b7143f"
SELL_AMOUNT="1420307757519717"
BUY_AMOUNT="1148153133427870"
VALID_TO="1773739033"
APP_DATA="0xd53f59b07e32a105fd0ae6c4ba266502c076c8b403e8ded07fd1129ddf5696d0"
FEE_AMOUNT="0"
KIND_HASH="0xf3b277728b3fee749481eb3e0b3b48980dbbab78658fc419025cb16eee346775"  # keccak256("sell")
PARTIALLY_FILLABLE="false"
SELL_BALANCE_HASH="0x5a28e9363bb942b639270062aa6bb295f434bcdfc42c97267bf003f272060dc9"  # keccak256("erc20")
BUY_BALANCE_HASH="0x5a28e9363bb942b639270062aa6bb295f434bcdfc42c97267bf003f272060dc9"   # keccak256("erc20")

# Constants
ORDER_TYPE_HASH="0xd5a25ba2e97094ad7d83dc28a6572da797d6b3e7fc6663bd93efb789fc17e489"
CHAIN_ID="8453"  # Base
SETTLEMENT="0x9008D19f58AAbD9eD0D60971565AA8510560ab41"

# 1. Struct hash = keccak256(abi.encode(typeHash, sellToken, buyToken, receiver, ...))
STRUCT_HASH=$(cast keccak256 "$(cast abi-encode \
    "f(bytes32,address,address,address,uint256,uint256,uint32,bytes32,uint256,bytes32,bool,bytes32,bytes32)" \
    "$ORDER_TYPE_HASH" \
    "$SELL_TOKEN" \
    "$BUY_TOKEN" \
    "$RECEIVER" \
    "$SELL_AMOUNT" \
    "$BUY_AMOUNT" \
    "$VALID_TO" \
    "$APP_DATA" \
    "$FEE_AMOUNT" \
    "$KIND_HASH" \
    "$PARTIALLY_FILLABLE" \
    "$SELL_BALANCE_HASH" \
    "$BUY_BALANCE_HASH")")
echo "Struct hash: $STRUCT_HASH"

# 2. Domain separator
DOMAIN_TYPE_HASH=$(cast keccak256 "$(cast --from-utf8 'EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)')")
NAME_HASH=$(cast keccak256 "$(cast --from-utf8 'Gnosis Protocol')")
VERSION_HASH=$(cast keccak256 "$(cast --from-utf8 'v2')")

DOMAIN_SEPARATOR=$(cast keccak256 "$(cast abi-encode \
    "f(bytes32,bytes32,bytes32,uint256,address)" \
    "$DOMAIN_TYPE_HASH" \
    "$NAME_HASH" \
    "$VERSION_HASH" \
    "$CHAIN_ID" \
    "$SETTLEMENT")")
echo "Domain separator: $DOMAIN_SEPARATOR"

# 3. EIP-712 hash = keccak256("\x19\x01" || domainSeparator || structHash)
EIP712_HASH=$(cast keccak256 "0x1901${DOMAIN_SEPARATOR#0x}${STRUCT_HASH#0x}")
echo "EIP-712 hash: $EIP712_HASH"

# 4. The signature from the order
SIGNATURE=""

# 5. Call isValidSignature on the signer
SIGNER="0xb4755fae3997fbe4becd34b4fc5a7f53d3b7143f"
echo ""
echo "isValidSignature call:"
echo "cast call $SIGNER 'isValidSignature(bytes32,bytes)(bytes4)' $EIP712_HASH $SIGNATURE --rpc-url <BASE_RPC_URL>"
